+)
+
+const reloadStatusFilename = "reload-status.json"
+
+// transactionalReloader makes a reload all-or-nothing as far as the individual
+// reloaders allow. It deliberately keeps the last successfully applied config
+// in memory; config.Config is immutable after LoadFile returns.
+type transactionalReloader struct {
+	mu       sync.RWMutex
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+	stateFile string
+	logger   *slog.Logger
+}
+
+func newTransactionalReloader(storageDir string, logger *slog.Logger) *transactionalReloader {
+	t := &transactionalReloader{stateFile: filepath.Join(storageDir, reloadStatusFilename), logger: logger}
+	b, err := os.ReadFile(t.stateFile)
+	if err != nil {
+		return t
+	}
+	if err := json.Unmarshal(b, &t.status); err != nil {
+		logger.Warn("Ignoring invalid persisted reload status", "file", t.stateFile, "err", err)
+	}
+	return t
+}
+
+func (t *transactionalReloader) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	return t.status.Clone()
+}
+
+func (t *transactionalReloader) setStatus(status api_v1.ReloadStatus) {
+	t.mu.Lock()
+	t.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		err = writeFileAtomic(t.stateFile, b)
+	}
+	t.mu.Unlock()
+	if err != nil {
+		t.logger.Warn("Failed to persist reload status", "file", t.stateFile, "err", err)
+	}
+}
+
+func writeFileAtomic(filename string, data []byte) error {
+	if err := os.MkdirAll(filepath.Dir(filename), 0o755); err != nil {
+		return err
+	}
+	tmp, err := os.CreateTemp(filepath.Dir(filename), ".reload-status-*")
+	if err != nil {
+		return err
+	}
+	tmpName := tmp.Name()
+	defer os.Remove(tmpName)
+	if _, err := tmp.Write(data); err != nil {
+		tmp.Close()
+		return err
+	}
+	if err := tmp.Chmod(0o644); err != nil {
+		tmp.Close()
+		return err
+	}
+	if err := tmp.Close(); err != nil {
+		return err
+	}
+	return os.Rename(tmpName, filename)
+}
+
+func (t *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		t.setStatus(api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ErrorCategory: "load_error", ErrorMessage: err.Error(), ReloaderTimingsMS: map[string]float64{}})
+		configSuccess.Set(0)
+		callback(false)
+		return err
+	}
+
+	status := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ReloaderTimingsMS: map[string]float64{}}
+	for i, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		if i > 0 && t.lastGood != nil {
+			status.RollbackAttempted = true
+			status.RollbackSuccessful = true
+			for _, applied := range rls[:i] {
+				if rollbackErr := applied.reloader(t.lastGood); rollbackErr != nil {
+					status.RollbackSuccessful = false
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("applying %s failed: %v; rolling back %s failed: %v", rl.name, err, applied.name, rollbackErr)
+					break
+				}
+			}
+		}
+		t.setStatus(status)
+		configSuccess.Set(0)
+		callback(false)
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	t.lastGood = conf
+	status.LastReloadSuccessful = true
+	status.ErrorCategory = "none"
+	t.setStatus(status)
+	configSuccess.Set(1)
+	configSuccessTime.SetToCurrentTime()
+	callback(true)
+	return nil
+}
+
+// loadInitial establishes the rollback target but intentionally does not record
+// an outcome: startup is not a reload attempt.
+func (t *transactionalReloader) loadInitial(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, rls ...reloader) error {
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		return err
+	}
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+		}
+	}
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	t.lastGood = conf
+	return nil
+}
